class Solution:
    def removeDuplicates(self, head: ListNode) -> ListNode:
        if not head:
            return head
        dup_set = set()
        prev = head
        while prev.next:
            if prev.val in dup_set:
                prev.next = prev.next.next
            else:
                dup_set.add(prev.val)
                prev = prev.next
        return head

