class Solution:
    ListNode* removeDuplicates(ListNode* head) {
        if (!head) return head;
        std::unordered_set<int> dup_set;
        ListNode* prev = head;
        while (prev->next) {
            if (dup_set.find(prev->val) != dup_set.end()) {
                prev->next = prev->next->next;
            } else {
                dup_set.insert(prev->val);
                prev = prev->next;
            }
        }
        return head;
    }
